def count_levels(lines):
    def level_of(line):
        start = line.find("[")
        end = line.find("]")
        if start == -1 or end == -1 or end < start:
            return "UNKNOWN"
        return line[start + 1:end]

    counts = {}
    for line in lines:
        level = level_of(line)
        counts[level] = counts.get(level, 0) + 1
    return counts
